# ─────────────────────────────────────────────
# Data model
# ─────────────────────────────────────────────

class LineType(Enum):
    ADDED = "added"
    REMOVED = "removed"
    CONTEXT = "context"


@dataclass
class DiffLine:
    line_type: LineType
    content: str          # raw text without the leading +/-/space
    old_lineno: Optional[int]  # None for added lines
    new_lineno: Optional[int]  # None for removed lines

    def __repr__(self) -> str:
        prefix = {
            LineType.ADDED: "+",
            LineType.REMOVED: "-",
            LineType.CONTEXT: " ",
        }[self.line_type]
        return f"DiffLine({prefix!r}, old={self.old_lineno}, new={self.new_lineno}, {self.content!r})"


@dataclass
class Hunk:
    old_start: int
    old_count: int
    new_start: int
    new_count: int
    section_heading: str          # optional function/class name after @@
    lines: list[DiffLine] = field(default_factory=list)

    @property
    def added_count(self) -> int:
        return sum(1 for l in self.lines if l.line_type == LineType.ADDED)

    @property
    def removed_count(self) -> int:
        return sum(1 for l in self.lines if l.line_type == LineType.REMOVED)

    def __repr__(self) -> str:
        return (
            f"Hunk(old={self.old_start},{self.old_count} "
            f"new={self.new_start},{self.new_count} "
            f"+{self.added_count}/-{self.removed_count})"
        )


@dataclass
class FileDiff:
    # paths
    old_path: Optional[str]       # None for new files
    new_path: Optional[str]       # None for deleted files
    original_path: Optional[str]  # set when renamed/copied

    # flags
    is_new_file: bool = False
    is_deleted_file: bool = False
    is_binary: bool = False
    is_renamed: bool = False
    is_copied: bool = False

    # mode
    old_mode: Optional[str] = None
    new_mode: Optional[str] = None

    # similarity (rename/copy percentage)
    similarity_index: Optional[int] = None  # 0-100

    # hunks (empty for binary / mode-only changes)
    hunks: list[Hunk] = field(default_factory=list)

    # ── aggregate stats ──────────────────────────────────────
    @property
    def added_lines(self) -> int:
        return sum(h.added_count for h in self.hunks)

    @property
    def removed_lines(self) -> int:
        return sum(h.removed_count for h in self.hunks)

    @property
    def display_path(self) -> str:
        if self.is_renamed or self.is_copied:
            return f"{self.original_path} → {self.new_path}"
        return self.new_path or self.old_path or "<unknown>"

    def __repr__(self) -> str:
        flags = []
        if self.is_new_file:    flags.append("new")
        if self.is_deleted_file: flags.append("deleted")
        if self.is_binary:      flags.append("binary")
        if self.is_renamed:     flags.append("renamed")
        if self.is_copied:      flags.append("copied")
        flag_str = f" [{', '.join(flags)}]" if flags else ""
        return (
            f"FileDiff({self.display_path!r}{flag_str} "
            f"+{self.added_lines}/-{self.removed_lines} "
            f"hunks={len(self.hunks)})"
        )


@dataclass
class DiffResult:
    files: list[FileDiff] = field(default_factory=list)

    @property
    def total_added(self) -> int:
        return sum(f.added_lines for f in self.files)

    @property
    def total_removed(self) -> int:
        return sum(f.removed_lines for f in self.files)

    def __repr__(self) -> str:
        return (
            f"DiffResult(files={len(self.files)} "
            f"+{self.total_added}/-{self.total_removed})"
        )


