def _strip_path_prefix(path: str) -> Optional[str]:
    """Remove a/ or b/ prefix added by git, handle /dev/null."""
    if path == "/dev/null":
        return None
    # git diff prefixes: a/ b/ i/ w/ c/ o/
    if re.match(r"^[a-z]/", path):
        return path[2:]
    return path


